mapper.insert:
INSERT INTO sys_user (
    username, password, nickname, email, phone, gender, avatar,
    dept_id, status, create_by, update_by, deleted
) VALUES (
    #{username}, #{password}, #{nickname}, #{email}, #{phone}, #{gender}, #{avatar},
    #{deptId}, #{status}, #{createBy}, #{updateBy}, #{deleted}
)

mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.phone, u.gender, u.avatar, u.dept_id, d.name AS dept_name, u.status, u.create_time FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id WHERE u.deleted = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.status = #{status}
AND u.dept_id = #{deptId}
ORDER BY u.create_time DESC
